#!/bin/bash
echo "当前是普通用户，请执行以下命令："
echo ""
echo "mkdir -p ~/.ssh"
echo "chmod 700 ~/.ssh"
echo "echo 'ssh-rsa  skp-t4n81gpwtwti66kkowj2' >> ~/.ssh/authorized_keys"
echo "chmod 600 ~/.ssh/authorized_keys"
echo ""
echo "然后切换到 root 用户："
echo "sudo -i"
echo ""
echo "在 root 用户下再添加一次："
echo "mkdir -p /root/.ssh"
echo "chmod 700 /root/.ssh"
echo "echo 'ssh-rsa  skp-t4n81gpwtwti66kkowj2' >> /root/.ssh/authorized_keys"
echo "chmod 600 /root/.ssh/authorized_keys"
